#!/usr/bin/env node
/**
 * MISAKA Network — Validator Startup Script
 *
 * Starts an L1 validator node with the key generated by generate-l1-key.js
 * and the staking proof from misakastake.com.
 *
 * Usage:
 *   node start-validator.js --key ./data/l1-secret-key.json [--stake-sig SOLANA_TX_SIG]
 *
 * Prerequisites:
 *   1. Generate key: node generate-l1-key.js
 *   2. Stake at https://misakastake.com
 *   3. Copy the Solana TX signature
 *
 * Options:
 *   --key PATH          Path to l1-secret-key.json (required)
 *   --stake-sig SIG     Solana TX signature from misakastake.com
 *   --rpc-port PORT     RPC port (default: 3001)
 *   --p2p-port PORT     P2P port (default: 6690)
 *   --peers ADDR,...    Static peers (comma-separated)
 *   --seeds ADDR,...    Seed nodes (comma-separated)
 *   --chain-id ID       Chain ID (default: 2 = testnet)
 *
 * ⚠  Solana private keys are NOT needed on this VPS.
 */

const { spawn } = require("child_process");
const path = require("path");
const fs = require("fs");

// ── Parse args ──
const args = process.argv.slice(2);
function getArg(name, defaultVal) {
  const idx = args.indexOf(`--${name}`);
  if (idx >= 0 && idx + 1 < args.length) return args[idx + 1];
  return defaultVal;
}
function hasFlag(name) {
  return args.includes(`--${name}`);
}

const keyPath = getArg("key", null);
const stakeSig = getArg("stake-sig", null);
const rpcPort = getArg("rpc-port", "3001");
const p2pPort = getArg("p2p-port", "6690");
const peers = getArg("peers", "");
const seeds = getArg("seeds", "");
const chainId = getArg("chain-id", "2");
const logLevel = getArg("log-level", "info");

// ── Validate --key ──
if (!keyPath) {
  console.error("");
  console.error("  ❌ --key is required.");
  console.error("");
  console.error("  Usage:");
  console.error("    node start-validator.js --key ./data/l1-secret-key.json");
  console.error("");
  console.error("  Generate a key first:");
  console.error("    node generate-l1-key.js");
  console.error("");
  process.exit(1);
}

if (!fs.existsSync(keyPath)) {
  console.error("");
  console.error(`  ❌ Key file not found: ${keyPath}`);
  console.error("");
  console.error("  Generate a key first:");
  console.error("    node generate-l1-key.js");
  console.error("");
  process.exit(1);
}

// ── Read key file ──
let keyFile;
try {
  keyFile = JSON.parse(fs.readFileSync(keyPath, "utf-8"));
} catch (err) {
  console.error(`  ❌ Failed to parse key file: ${err.message}`);
  process.exit(1);
}

if (keyFile.format !== "misaka-l1-key") {
  console.error(`  ❌ Invalid key file format: expected 'misaka-l1-key', got '${keyFile.format}'`);
  process.exit(1);
}

const dataDir = path.dirname(keyPath);
const nodeName = keyFile.nodeName || "misaka-validator";

console.log("");
console.log("══════════════════════════════════════════════════");
console.log("  MISAKA L1 Validator");
console.log("══════════════════════════════════════════════════");
console.log("");
console.log(`  Node Name:      ${nodeName}`);
console.log(`  L1 Public Key:  ${keyFile.l1PublicKey}`);
console.log(`  Validator ID:   ${keyFile.validatorId}`);
console.log(`  Chain ID:       ${chainId}`);
console.log(`  RPC Port:       ${rpcPort}`);
console.log(`  P2P Port:       ${p2pPort}`);
console.log(`  Data Dir:       ${dataDir}`);

if (stakeSig) {
  console.log(`  Stake Sig:      ${stakeSig.substring(0, 20)}...`);
} else {
  console.log(`  Stake Sig:      ⚠ NOT PROVIDED`);
  console.log("");
  console.log("  ⚠  Without a staking signature from misakastake.com,");
  console.log("     the validator will register but CANNOT activate.");
  console.log("     Stake at https://misakastake.com and restart with --stake-sig.");
}
console.log("");

// ── Prepare the encrypted keystore for the node ──
// The node expects dag_validator_0.enc.json. If it doesn't exist,
// write the plaintext key so the node auto-migrates to encrypted format.
const encPath = path.join(dataDir, "dag_validator_0.enc.json");
const plaintextPath = path.join(dataDir, "dag_validator_0.json");

if (!fs.existsSync(encPath) && !fs.existsSync(plaintextPath)) {
  // Write plaintext format that the node will auto-migrate to encrypted
  const nodeKeyFile = {
    validator_id_hex: keyFile.validatorId,
    public_key_hex: keyFile.mlDsaPublicKey,
    secret_key_hex: keyFile.mlDsaSecretKey,
    stake_weight: 1000000,
  };
  fs.writeFileSync(plaintextPath, JSON.stringify(nodeKeyFile, null, 2));
  fs.chmodSync(plaintextPath, 0o600);
  console.log(`  📝 Wrote node key file: ${plaintextPath}`);
  console.log("     (will be auto-encrypted on first start)");
  console.log("");
}

// ── Find the misaka-node binary ──
const binaryPaths = [
  path.join(__dirname, "..", "target", "release", "misaka-node"),
  path.join(__dirname, "..", "target", "debug", "misaka-node"),
  "misaka-node",
];

let binaryPath = null;
for (const p of binaryPaths) {
  try {
    require("child_process").execSync(`${p} --version`, { stdio: "pipe" });
    binaryPath = p;
    break;
  } catch (_) {}
}

if (!binaryPath) {
  console.error("  ❌ misaka-node binary not found.");
  console.error("     Build: cargo build --release --features dag");
  process.exit(1);
}

// ── Build command ──
const nodeArgs = [
  "--validator",
  "--name", nodeName,
  "--chain-id", chainId,
  "--data-dir", dataDir,
  "--rpc-port", rpcPort,
  "--p2p-port", p2pPort,
  "--log-level", logLevel,
];

if (stakeSig) {
  nodeArgs.push("--stake-signature", stakeSig);
}
if (peers) {
  nodeArgs.push("--peers", peers);
}
if (seeds) {
  nodeArgs.push("--seeds", seeds);
}

console.log(`  🚀 Starting: ${binaryPath} ${nodeArgs.join(" ")}`);
console.log("");
console.log("══════════════════════════════════════════════════");
console.log("");

// ── Start the node ──
const child = spawn(binaryPath, nodeArgs, {
  stdio: "inherit",
  env: {
    ...process.env,
    // Pass stake signature via env var too (belt and suspenders)
    ...(stakeSig ? { MISAKA_STAKE_SIGNATURE: stakeSig } : {}),
  },
});

child.on("exit", (code) => {
  if (code !== 0) {
    console.error(`\n  ❌ Node exited with code ${code}`);
  }
  process.exit(code || 0);
});

// Forward signals for graceful shutdown
["SIGINT", "SIGTERM"].forEach((sig) => {
  process.on(sig, () => {
    console.log(`\n  Received ${sig}, shutting down...`);
    child.kill(sig);
  });
});
